stats.proof_process_distincts:
forall x, y | x != y && 0 <= x <= y < |xs+ys|
    ensures (xs+ys)[x] != (xs+ys)[y]
{
    if 0 <= x < |xs| && 0 <= y < |xs| {
        // Both indices in xs portion
        assert (xs+ys)[x] == xs[x];
        assert (xs+ys)[y] == xs[y];
        assert distinct(xs);
    } else if |xs| <= x < |xs+ys| && |xs| <= y < |xs+ys| {
        // Both indices in ys portion
        assert (xs+ys)[x] == ys[x-|xs|];
        assert (xs+ys)[y] == ys[y-|xs|];
        assert distinct(ys);
    } else {
        // Cross case: x in xs portion, y in ys portion
        assert 0 <= x < |xs|;
        assert |xs| <= y < |xs+ys|;
        assert (xs+ys)[x] == xs[x];
        assert (xs+ys)[y] == ys[y-|xs|];
        assert xs[x] in xs;
        assert xs[x] !in ys;
        notInNotEqual(ys, xs[x]);
        assert (xs+ys)[x] != (xs+ys)[y];
    }
}

stats.proof_process_pigeonHolesMultiset:
if x :| multiset(list)[x] > 1 {
            // x is the direct witness
            assert multiset(list)[x] > 1;
        } else if x :| multiset(list)[x] == 1 {
            assert x in list;
            var i :| 0 <= i < |list| && list[i] == x;
            assert list == list[..i] + [x] + list[i+1..];
            assert multiset(list) == multiset(list[..i]) + multiset(list[i+1..]) + multiset{x};
            assert multiset(list)[x] == 1;
            var rest := list[..i] + list[i+1..];
            assert multiset(rest)[x] == 0;
            assert multiset(rest) == multiset(list) - multiset{x};
            forall y | y in rest
                ensures y in items - {x}
            {
                assert y in items;
                assert y != x;
            }
            assert x in items;
            assert |items - {x}| == n - 1;
            assert |rest| == |list| - 1;
            assert |rest| > n - 1;
            pigeonHolesMultiset(items - {x}, rest, n - 1);
            var item :| multiset(rest)[item] > 1;
            // item != x because multiset(rest)[x] == 0
            assert item != x;
            assert multiset(list)[item] == multiset(rest)[item] + multiset{x}[item];
            assert multiset{x}[item] == 0;
            assert multiset(list)[item] > 1;
        } else if x :| multiset(list)[x] == 0 {
            // This branch is unreachable: list is non-empty (|list| > n >= 0)
            // so list[0] exists and multiset(list)[list[0]] >= 1
            assert |list| > 0;
            var first := list[0];
            assert first in list;
            assert multiset(list)[first] >= 1;
            // But we assumed all elements have multiplicity 0 or we're in else branches
            // meaning no element has multiplicity > 1 or == 1, so all have multiplicity 0
            // But first has multiplicity >= 1, contradiction
            assert multiset(list)[first] == 0 || multiset(list)[first] == 1 || multiset(list)[first] > 1;
            assert false;
        }

