stats.proof_process_transitiveUnion:
assume forall a :: a in S_1+S_2 ==> a !in S_1 || a !in S_2;
    forall a, b, c | a in S_1+S_2 && b in S_1+S_2 && c in S_1+S_2 && (a,b) in R_1+R_2 && (b,c) in R_1+R_2
        ensures (a,c) in R_1+R_2
    {
        if a in S_1 && b in S_1 && c in S_1 && (a,b) in R_1 && (b,c) in R_1 {
            assert (a,c) in R_1;
            assert (a,c) in R_1+R_2;
        } else if a in S_2 && b in S_2 && c in S_2 && (a,b) in R_2 && (b,c) in R_2 {
            assert (a,c) in R_2;
            assert (a,c) in R_1+R_2;
        } else {
            // Cross-relation case: impossible under disjointness
            // If (a,b) in R_1, then b in S_1 (from relationOnASet)
            // If (b,c) in R_2, then b in S_2 (from relationOnASet)
            // But disjointness says b !in S_1 || b !in S_2 -- contradiction
            if (a,b) in R_1 {
                assert b in S_1;
                if (b,c) in R_2 {
                    assert b in S_2;
                    assert b !in S_1 || b !in S_2;
                    assert false;
                } else {
                    assert (b,c) in R_1;
                    assert (a,c) in R_1;
                    assert (a,c) in R_1+R_2;
                }
            } else {
                assert (a,b) in R_2;
                assert b in S_2;
                if (b,c) in R_1 {
                    assert b in S_1;
                    assert b !in S_1 || b !in S_2;
                    assert false;
                } else {
                    assert (b,c) in R_2;
                    assert (a,c) in R_2;
                    assert (a,c) in R_1+R_2;
                }
            }
        }
    }

stats.proof_process_EverLongerSkinnyTrees_Lemm:
if n == 0 {
    // Tail(EverLongerSkinnyTrees(k), 0) = EverLongerSkinnyTrees(k) = Cons(SkinnyFiniteTree(k), ...)
    // Both postconditions follow directly from definitions
    assert Tail(EverLongerSkinnyTrees(k), 0) == EverLongerSkinnyTrees(k);
    assert EverLongerSkinnyTrees(k) == Cons(SkinnyFiniteTree(k), EverLongerSkinnyTrees(k+1));
  } else {
    // Inductive hypothesis at (k, n-1): Tail(EverLongerSkinnyTrees(k), n-1).Cons?
    EverLongerSkinnyTrees_Lemma(k, n-1);
    // This gives us Tail(EverLongerSkinnyTrees(k), n-1).Cons?
    // which we need for Tail_Lemma0

    // Tail_Lemma0: Tail(s, n-1).tail == Tail(s.tail, n-1) when s.Cons? and Tail(s, n-1).Cons?
    assert EverLongerSkinnyTrees(k).Cons?;
    Tail_Lemma0(EverLongerSkinnyTrees(k), n-1);
    // Now: Tail(EverLongerSkinnyTrees(k), n-1).tail == Tail(EverLongerSkinnyTrees(k).tail, n-1)

    // EverLongerSkinnyTrees(k).tail == EverLongerSkinnyTrees(k+1)
    assert EverLongerSkinnyTrees(k) == Cons(SkinnyFiniteTree(k), EverLongerSkinnyTrees(k+1));
    assert EverLongerSkinnyTrees(k).tail == EverLongerSkinnyTrees(k+1);

    // Inductive hypothesis at (k+1, n-1)
    EverLongerSkinnyTrees_Lemma(k+1, n-1);
    // Tail(EverLongerSkinnyTrees(k+1), n-1).Cons?
    // Tail(EverLongerSkinnyTrees(k+1), n-1).head == SkinnyFiniteTree((k+1)+(n-1)) == SkinnyFiniteTree(k+n)

    // Now chain: Tail(EverLongerSkinnyTrees(k), n)
    // = Tail(EverLongerSkinnyTrees(k), n-1).tail   (by def of Tail, since n > 0 and Tail(...,n-1).Cons?)
    // = Tail(EverLongerSkinnyTrees(k).tail, n-1)   (by Tail_Lemma0)
    // = Tail(EverLongerSkinnyTrees(k+1), n-1)      (by unfolding .tail)

    calc {
      Tail(EverLongerSkinnyTrees(k), n);
      Tail(EverLongerSkinnyTrees(k), n-1).tail;
      { Tail_Lemma0(EverLongerSkinnyTrees(k), n-1); }
      Tail(EverLongerSkinnyTrees(k).tail, n-1);
      Tail(EverLongerSkinnyTrees(k+1), n-1);
    }

    assert Tail(EverLongerSkinnyTrees(k), n) == Tail(EverLongerSkinnyTrees(k+1), n-1);
    assert Tail(EverLongerSkinnyTrees(k+1), n-1).Cons?;
    assert Tail(EverLongerSkinnyTrees(k+1), n-1).head == SkinnyFiniteTree((k+1)+(n-1));
    assert (k+1)+(n-1) == k+n;
  }

