stats.proof_process_Expon23:
if n == 0 {
    assert (expo(2, 3 * 0) - expo(3, 0)) % 5 == 0;
} else if n == 1 {
    assert (expo(2, 3) - expo(3, 1)) % 5 == 0;
} else {
    // n >= 2, so n-1 >= 1 is a valid nat
    Expon23(n - 1);
    // Prove expo(2, 3*n) == 8 * expo(2, 3*(n-1)) by unfolding expo 3 times
    assert 3 * n == 3 * (n - 1) + 3;
    assert expo(2, 3 * n) == 2 * expo(2, 3 * n - 1);
    assert expo(2, 3 * n - 1) == 2 * expo(2, 3 * n - 2);
    assert expo(2, 3 * n - 2) == 2 * expo(2, 3 * n - 3);
    assert 3 * n - 3 == 3 * (n - 1);
    assert expo(2, 3 * n) == 8 * expo(2, 3 * (n - 1));
    // Prove expo(3, n) == 3 * expo(3, n-1) by unfolding expo once
    assert expo(3, n) == 3 * expo(3, n - 1);
    assert expo(2, 3) == 8;
    assert expo(3, 1) == 3;
    var a := expo(2, 3 * (n - 1));
    var b := expo(3, n - 1);
    assert (a - b) % 5 == 0;
    assert expo(2, 3 * n) - expo(3, n) == 8 * a - 3 * b;
    assert 8 * a - 3 * b == 3 * (a - b) + 5 * a;
    assert (3 * (a - b)) % 5 == 0;
    assert (5 * a) % 5 == 0;
    assert (3 * (a - b) + 5 * a) % 5 == 0;
}

