stats.proof_process_Lucas_Theorem':
if m == 0 && n == 0 {
    // binom(0,0) = 1 which is odd, BitSet(0) = {} <= {} = BitSet(0)
  } else if EVEN(n) && !EVEN(m) {
    // binom(n,m) is even, and 0 in BitSet(m) but 0 !in BitSet(n)
    Lucas_Binary''(n, m);
    assert 0 in BitSet(m) by {
      assert Bit(0, m) by { assert m % 2 == 1; }
      BitSize(0, m);
    }
    assert 0 !in BitSet(n) by {
      assert !Bit(0, n) by { assert n % 2 == 0; }
    }
    assert !(BitSet(m) <= BitSet(n));
  } else {
    var m' := m / 2;
    var n' := n / 2;
    Lucas_Binary''(n, m);
    Lucas_Theorem'(m', n');
    // Now we know: !EVEN(binom(n,m)) == !EVEN(binom(n',m')) == (BitSet(m') <= BitSet(n'))
    // Need to show: BitSet(m') <= BitSet(n') <==> BitSet(m) <= BitSet(n)
    BitSet_Property(m);
    BitSet_Property(n);
    SucElements(BitSet(m'));
    SucElements(BitSet(n'));
    // BitSet(m) - {0} == Suc(BitSet(m'))
    // BitSet(n) - {0} == Suc(BitSet(n'))
    // Need: Suc(BitSet(m')) <= Suc(BitSet(n')) <==> BitSet(m') <= BitSet(n')
    assert (BitSet(m') <= BitSet(n')) <==> (Suc(BitSet(m')) <= Suc(BitSet(n'))) by {
      if BitSet(m') <= BitSet(n') {
        forall x | x in Suc(BitSet(m')) ensures x in Suc(BitSet(n')) {
          SucElements(BitSet(m'));
          SucElements(BitSet(n'));
          assert (x-1) in BitSet(m');
          assert (x-1) in BitSet(n');
        }
      } else {
        var wit :| wit in BitSet(m') && wit !in BitSet(n');
        SucElements(BitSet(m'));
        SucElements(BitSet(n'));
        assert (wit+1) in Suc(BitSet(m'));
        assert (wit+1) !in Suc(BitSet(n'));
      }
    }
    // Now connect removing {0} to the full sets
    // We are NOT in the case EVEN(n) && !EVEN(m)
    // Either EVEN(m): 0 !in BitSet(m), so BitSet(m) == BitSet(m) - {0}
    // Or !EVEN(m) && !EVEN(n): 0 in both, so subset relation unaffected
    assert (BitSet(m) - {0} <= BitSet(n) - {0}) <==> (BitSet(m) <= BitSet(n)) by {
      if EVEN(m) {
        assert 0 !in BitSet(m);
        assert BitSet(m) - {0} == BitSet(m);
        if BitSet(m) <= BitSet(n) {
          assert BitSet(m) - {0} <= BitSet(n) - {0};
        }
        if BitSet(m) - {0} <= BitSet(n) - {0} {
          forall x | x in BitSet(m) ensures x in BitSet(n) {
            assert x in BitSet(m) - {0};
            assert x in BitSet(n) - {0};
          }
        }
      } else {
        // !EVEN(m) and !EVEN(n) (since we excluded EVEN(n) && !EVEN(m))
        assert !EVEN(m) && !EVEN(n);
        assert Bit(0, m);
        assert Bit(0, n);
        BitSize(0, m);
        BitSize(0, n);
        assert 0 in BitSet(m);
        assert 0 in BitSet(n);
        if BitSet(m) <= BitSet(n) {
          assert BitSet(m) - {0} <= BitSet(n) - {0};
        }
        if BitSet(m) - {0} <= BitSet(n) - {0} {
          forall x | x in BitSet(m) ensures x in BitSet(n) {
            if x == 0 { } else {
              assert x in BitSet(m) - {0};
              assert x in BitSet(n) - {0};
            }
          }
        }
      }
    }
  }

