        Bind(Bind(Cons(x, xs), f), g);
        == Bind(append(Nil, Bind(xs, f)), g);
        == Bind(Bind(xs, f), g);
        == { Associativity(xs, f, g); }
           Bind(xs, y => Bind(f(y), g));
        == append(Nil, Bind(xs, y => Bind(f(y), g)));
        == append(Bind(Nil, g), Bind(xs, y => Bind(f(y), g)));
        == Bind(Cons(x, xs), z => Bind(f(z), g));
      }
    case Cons(y, ys) =>
      calc {
        Bind(Bind(Cons(x, xs), f), g);
        == Bind(append(Cons(y, ys), Bind(xs, f)), g);
        == { BindOverAppend(Cons(y, ys), Bind(xs, f), g); }
           append(Bind(Cons(y, ys), g), Bind(Bind(xs, f), g));
        == append(append(g(y), Bind(ys, g)), Bind(Bind(xs, f), g));
        == { AppendAssoc(g(y), Bind(ys, g), Bind(Bind(xs, f), g)); }
           append(g(y), append(Bind(ys, g), Bind(Bind(xs, f), g)));
        == { Associativity(xs, f, g); }
           append(g(y), append(Bind(ys, g), Bind(xs, z => Bind(f(z), g))));
        == { AppendAssoc(g(y), Bind(ys, g), Bind(xs, z => Bind(f(z), g))); }
           append(append(g(y), Bind(ys, g)), Bind(xs, z => Bind(f(z), g)));
        == append(Bind(Cons(y, ys), g), Bind(xs, z => Bind(f(z), g)));
        == { assert f(x) == Cons(y, ys); }
           append(Bind(f(x), g), Bind(xs, z => Bind(f(z), g)));
        == Bind(Cons(x, xs), z => Bind(f(z), g));
      }

