      // Safety: v'.decision == v.decision, so Safety(v') follows from Safety(v)
      // Single vote: v.votes[n] == {}, so v'.votes[n] = {c}, still at most one vote
      // ChoiceQuorum: v'.decision == v.decision, and v'.votes[n] has one more vote
      //   but ChoiceQuorum only requires votes for quorum members, and votes only grow
      assert v'.WF();
      assert Safety(v');
      assert forall n2, v1, v2 :: v1 in v'.votes[n2] && v2 in v'.votes[n2] ==> v1 == v2 by {
        forall n2, v1, v2 | v1 in v'.votes[n2] && v2 in v'.votes[n2]
          ensures v1 == v2
        {
          if n2 == n {
            // v.votes[n] == {}, so v'.votes[n] = {c}
            assert v1 == c;
            assert v2 == c;
          } else {
            assert v'.votes[n2] == v.votes[n2];
          }
        }
      }
      assert forall c2 :: c2 in v'.decision ==> exists q:Quorum :: ChoiceQuorum(v', q, c2) by {
        forall c2 | c2 in v'.decision
          ensures exists q:Quorum :: ChoiceQuorum(v', q, c2)
        {
          // v'.decision == v.decision
          assert c2 in v.decision;
          var q :| ChoiceQuorum(v, q, c2);
          // ChoiceQuorum(v', q, c2): for all n2 in q, c2 in v'.votes[n2]
          // v'.votes[n2] >= v.votes[n2], so this holds
          assert ChoiceQuorum(v', q, c2) by {
            forall n2 | Member(n2, q)
              ensures c2 in v'.votes[n2]
            {
              assert c2 in v.votes[n2];
              if n2 == n {
                assert v'.votes[n2] == v.votes[n2] + {c};
              } else {
                assert v'.votes[n2] == v.votes[n2];
              }
            }
          }
        }
      }
    }
    case DecideStep(c, q) => {
      // v'.decision = v.decision + {step.c}, v'.votes = v.votes
      assert v'.WF();
      assert v'.votes == v.votes;
      // Single vote invariant: votes unchanged
      assert forall n2, v1, v2 :: v1 in v'.votes[n2] && v2 in v'.votes[n2] ==> v1 == v2;
      // ChoiceQuorum for v'.decision
      assert forall c2 :: c2 in v'.decision ==> exists q2:Quorum :: ChoiceQuorum(v', q2, c2) by {
        forall c2 | c2 in v'.decision
          ensures exists q2:Quorum :: ChoiceQuorum(v', q2, c2)
        {
          if c2 in v.decision {
            var q2 :| ChoiceQuorum(v, q2, c2);
            assert ChoiceQuorum(v', q2, c2);
          } else {
            // c2 == step.c
            assert c2 == step.c;
            assert ChoiceQuorum(v', step.q, c2) by {
              forall n2 | Member(n2, step.q)
                ensures c2 in v'.votes[n2]
              {
                assert step.c in v.votes[n2];
              }
            }
          }
        }
      }
      // Safety
      assert Safety(v') by {
        forall c1, c2 | c1 in v'.decision && c2 in v'.decision
          ensures c1 == c2
        {
          if c1 in v.decision && c2 in v.decision {
            assert Safety(v);
          } else if c1 !in v.decision && c2 !in v.decision {
            assert c1 == step.c;
            assert c2 == step.c;
          } else if c1 !in v.decision {
            // c1 == step.c, c2 in v.decision
            assert c1 == step.c;
            var q2 :| ChoiceQuorum(v, q2, c2);
            var n2 := QuorumIntersect(step.q, q2);
            assert step.c in v.votes[n2];
            assert c2 in v.votes[n2];
          } else {
            // c2 == step.c, c1 in v.decision
            assert c2 == step.c;
            var q1 :| ChoiceQuorum(v, q1, c1);
            var n2 := QuorumIntersect(q1, step.q);
            assert c1 in v.votes[n2];
            assert step.c in v.votes[n2];
          }
        }
      }
    }
  }

