stats.proof_process_DifferentPermutationSameSu:
if s1 == [] {
    if s2 != [] {
        var y := s2[0];
        assert y in s2;
        assert multiset(s2)[y] > 0;
        assert multiset(s1)[y] == 0;
        assert false;
    }
    assert s2 == [];
    assert seq_sum(s1) == 0;
    assert seq_sum(s2) == 0;
} else {
    var x := s1[0];

    assert multiset(s1)[x] > 0;
    assert multiset(s2)[x] > 0;
    assert x in multiset(s2);
    assert x in s2;

    var i2 :| 0 <= i2 < |s2| && s2[i2] == x;

    var remaining1 := s1[1..];
    assert s1 == [x] + remaining1;
    SeqPartsSameSum(s1, [x], remaining1);
    assert seq_sum(s1) == x + seq_sum(remaining1);

    var s2_left := s2[..i2];
    var s2_right := s2[i2+1..];
    assert s2 == s2_left + [x] + s2_right;
    SeqPartsSameSum(s2, s2_left + [x], s2_right);
    SeqPartsSameSum(s2_left + [x], s2_left, [x]);
    assert seq_sum(s2) == seq_sum(s2_left) + x + seq_sum(s2_right);

    var remaining2 := s2_left + s2_right;
    SeqPartsSameSum(remaining2, s2_left, s2_right);
    assert seq_sum(remaining2) == seq_sum(s2_left) + seq_sum(s2_right);

    assert multiset(s1) == multiset([x]) + multiset(remaining1);
    assert multiset(s2_left) + multiset([x]) + multiset(s2_right) == multiset(s2);
    assert multiset(remaining2) == multiset(s2_left) + multiset(s2_right);

    // Explicit multiset subtraction to help Dafny
    var mx := multiset([x]);
    assert multiset(s1) - mx == multiset(remaining1);
    assert multiset(s2) - mx == multiset(s2_left) + multiset(s2_right);
    assert multiset(s2) - mx == multiset(remaining2);
    assert multiset(s1) - mx == multiset(s2) - mx;
    assert multiset(remaining1) == multiset(remaining2);

    DifferentPermutationSameSum(remaining1, remaining2);
    assert seq_sum(remaining1) == seq_sum(remaining2);

    assert seq_sum(s1) == x + seq_sum(remaining1);
    assert seq_sum(s2) == seq_sum(s2_left) + x + seq_sum(s2_right);
    assert seq_sum(remaining2) == seq_sum(s2_left) + seq_sum(s2_right);
    assert seq_sum(s1) == seq_sum(s2);
}

stats.proof_process_BinarySearch:
var lo: nat := 0;
    var hi: nat := |intSeq|;
    while lo < hi
        invariant 0 <= lo <= hi <= |intSeq|
        invariant forall i:nat | 0 <= i < lo :: intSeq[i] < key
        invariant forall i:nat | hi <= i < |intSeq| :: intSeq[i] > key
    {
        var mid := (lo + hi) / 2;
        if intSeq[mid] < key {
            assert forall i:nat | lo <= i <= mid :: intSeq[i] <= intSeq[mid];
            lo := mid + 1;
        } else if intSeq[mid] > key {
            assert forall i:nat | mid <= i < |intSeq| :: intSeq[i] >= intSeq[mid];
            hi := mid;
        } else {
            assert intSeq[mid] == key;
            return mid;
        }
    }
    return -1;

