stats.proof_process_DeleteMinCorrect:
var pq' := DeleteMin(pq);
        if pq.left.Leaf? || pq.right.Leaf? {
            // By IsBalanced, pq.left.Leaf? ==> pq.right.Leaf?
            // So pq.right.Leaf? holds in both sub-cases
            // DeleteMin returns pq.left
            assert pq' == pq.left;
            // Elements: Elements(pq) = multiset{pq.x} + Elements(pq.left) + Elements(pq.right)
            // Since pq.right.Leaf?, Elements(pq.right) = multiset{}
            assert Elements(pq') + multiset{pq.x} == Elements(pq);
            assert Valid(pq');
            assert |Elements(pq')| == |Elements(pq)| - 1;
        } else {
            // Both children are Nodes
            assert pq.left.Node? && pq.right.Node?;
            // Recurse on pq.left
            DeleteMinCorrect(pq.left);
            var leftMin := DeleteMin(pq.left);
            // DeleteMinCorrect(pq.left) gives us:
            // Valid(leftMin) && Elements(leftMin) + multiset{pq.left.x} == Elements(pq.left)
            // && |Elements(leftMin)| == |Elements(pq.left)| - 1
            if pq.left.x <= pq.right.x {
                // DeleteMin returns Node(pq.left.x, pq.right, DeleteMin(pq.left))
                assert pq' == Node(pq.left.x, pq.right, leftMin);
                // Elements proof
                calc {
                    Elements(pq') + multiset{pq.x};
                ==
                    (multiset{pq.left.x} + Elements(pq.right) + Elements(leftMin)) + multiset{pq.x};
                == { DeleteMinCorrect(pq.left); }
                    (multiset{pq.left.x} + Elements(pq.right) + (Elements(pq.left) - multiset{pq.left.x})) + multiset{pq.x};
                ==
                    Elements(pq);
                }
                // IsBinaryHeap proof
                assert IsBinaryHeap(pq.right);
                assert IsBinaryHeap(leftMin);
                // pq.left.x <= pq.right.x (given)
                // pq.left.x <= leftMin.x: leftMin elements are subset of pq.left elements
                // pq.left.x is min of pq.left, so pq.left.x <= everything in Elements(pq.left)
                // leftMin elements are in Elements(pq.left), so pq.left.x <= leftMin.x
                if leftMin.Node? {
                    assert leftMin.x in Elements(leftMin);
                    assert Elements(leftMin) <= Elements(pq.left);
                    BinaryHeapStoresMin(pq.left, leftMin.x);
                    assert pq.left.x <= leftMin.x;
                }
                assert IsBinaryHeap(pq');
                // IsBalanced proof
                // |Elements(pq.right)| and |Elements(leftMin)| = |Elements(pq.left)| - 1
                // Original: |Elements(pq.left)| == |Elements(pq.right)| or |Elements(pq.left)| == |Elements(pq.right)| + 1
                // New left = pq.right, new right = leftMin
                // new |left| = |Elements(pq.right)|, new |right| = |Elements(pq.left)| - 1
                // Case 1: |pq.left| == |pq.right| => new |left| = |pq.right| = |pq.left| = |pq.left|-1+1 = new|right|+1 ✓
                // Case 2: |pq.left| == |pq.right|+1 => new |left| = |pq.right| = |pq.left|-1 = new|right| ✓
                assert IsBalanced(pq.right);
                assert IsBalanced(leftMin);
                assert IsBalanced(pq');
                assert Valid(pq');
            } else {
                // pq.left.x > pq.right.x
                // DeleteMin returns Node(pq.right.x, ReplaceRoot(pq.right, pq.left.x), DeleteMin(pq.left))
                ReplaceRootCorrect(pq.right, pq.left.x);
                var rr := ReplaceRoot(pq.right, pq.left.x);
                assert pq' == Node(pq.right.x, rr, leftMin);
                // Elements proof
                calc {
                    Elements(pq') + multiset{pq.x};
                ==
                    (multiset{pq.right.x} + Elements(rr) + Elements(leftMin)) + multiset{pq.x};
                == { ReplaceRootCorrect(pq.right, pq.left.x); }
                    (multiset{pq.right.x} + (Elements(pq.right) + multiset{pq.left.x} - multiset{pq.right.x}) + Elements(leftMin)) + multiset{pq.x};
                == { DeleteMinCorrect(pq.left); }
                    (Elements(pq.right) + multiset{pq.left.x} + (Elements(pq.left) - multiset{pq.left.x})) + multiset{pq.x};
                ==
                    Elements(pq);
                }
                // IsBinaryHeap
                assert IsBinaryHeap(rr);
                assert IsBinaryHeap(leftMin);
                // pq.right.x <= rr.x: pq.left.x in Elements(rr), pq.right.x < pq.left.x, rr is valid heap
                assert pq.left.x in Elements(rr);
                if rr.Node? {
                    BinaryHeapStoresMin(rr, rr.x);
                    assert rr.x <= rr.x;
                }
                // pq.right.x is min of pq.right, pq.left.x in Elements(rr)
                // Need pq.right.x <= rr.x
                if rr.Node? {
                    assert rr.x in Elements(rr);
                    // rr is valid, so rr.x is min of rr
                    BinaryHeapStoresMin(rr, pq.left.x);
                    assert rr.x <= pq.left.x;
                    // pq.right.x < pq.left.x (from else branch: pq.left.x > pq.right.x)
                    // but we need pq.right.x <= rr.x
                    // rr.x is min of Elements(rr) = Elements(pq.right) + {pq.left.x} - {pq.right.x}
                    // pq.right.x is min of pq.right, so pq.right.x <= everything in Elements(pq.right)
                    // Elements(rr) = Elements(pq.right) - {pq.right.x} + {pq.left.x}
                    // everything in Elements(pq.right)-{pq.right.x} >= pq.right.x
                    // pq.left.x > pq.right.x
                    // so pq.right.x <= rr.x
                    assert Elements(rr) == Elements(pq.right) + multiset{pq.left.x} - multiset{pq.right.x};
                    forall y | y in Elements(rr) ensures pq.right.x <= y {
                        if y == pq.left.x {
                            assert pq.right.x < pq.left.x;
                        } else {
                            assert y in Elements(pq.right);
                            BinaryHeapStoresMin(pq.right, y);
                        }
                    }
                    assert pq.right.x <= rr.x;
                }
                // pq.right.x <= leftMin.x
                if leftMin.Node? {
                    assert leftMin.x in Elements(leftMin);
                    assert Elements(leftMin) <= Elements(pq.left);
                    BinaryHeapStoresMin(pq.left, leftMin.x);
                    assert pq.left.x <= leftMin.x;
                    assert pq.right.x < pq.left.x;
                    assert pq.right.x <= leftMin.x;
                }
                assert IsBinaryHeap(pq');
                // IsBalanced
                assert IsBalanced(rr);
                assert IsBalanced(leftMin);
                assert |Elements(rr)| == |Elements(pq.right)|;
                assert |Elements(leftMin)| == |Elements(pq.left)| - 1;
                assert IsBalanced(pq');
                assert Valid(pq');
            }
        }

