stats.proof_process_CountProject:
match xs {
  case Nil =>
    match ys {
      case Nil => // trivial
      case Cons(yhd, ytl) =>
        if yhd == p {
          // Project(Nil, p) = Nil, but Project(Cons(yhd, ytl), p) = Cons(p, Project(ytl, p)) != Nil
          // This case is contradictory
          assert Project(ys, p) == Cons(yhd, Project(ytl, p));
          assert Project(xs, p) == Nil;
          // contradiction with hypothesis
        } else {
          // Project(Cons(yhd, ytl), p) = Project(ytl, p) = Nil
          // Count(Cons(yhd, ytl), p) = Count(ytl, p)
          CountProject(Nil, ytl, p);
        }
    }
  case Cons(xhd, xtl) =>
    match ys {
      case Nil =>
        if xhd == p {
          // Project(Cons(xhd, xtl), p) = Cons(p, Project(xtl, p)) != Nil = Project(Nil, p)
          // contradiction
          assert Project(xs, p) == Cons(xhd, Project(xtl, p));
          assert Project(ys, p) == Nil;
        } else {
          // Project(Cons(xhd, xtl), p) = Project(xtl, p) = Nil
          CountProject(xtl, Nil, p);
        }
      case Cons(yhd, ytl) =>
        if xhd == p && yhd == p {
          // Project(xs, p) = Cons(p, Project(xtl, p))
          // Project(ys, p) = Cons(p, Project(ytl, p))
          // So Project(xtl, p) == Project(ytl, p)
          assert Project(xs, p) == Cons(xhd, Project(xtl, p));
          assert Project(ys, p) == Cons(yhd, Project(ytl, p));
          CountProject(xtl, ytl, p);
        } else if xhd == p && yhd != p {
          // Project(xs, p) = Cons(p, Project(xtl, p))
          // Project(ys, p) = Project(ytl, p)
          // So Project(xs, p) == Project(ytl, p)... keep xs, peel yhd from ys
          assert Project(ys, p) == Project(ytl, p);
          CountProject(xs, ytl, p);
        } else if xhd != p && yhd == p {
          // Project(xs, p) = Project(xtl, p)
          // Project(ys, p) = Cons(p, Project(ytl, p))
          // peel xhd from xs, keep ys
          assert Project(xs, p) == Project(xtl, p);
          CountProject(xtl, ys, p);
        } else {
          // xhd != p && yhd != p
          // Project(xs, p) = Project(xtl, p)
          // Project(ys, p) = Project(ytl, p)
          assert Project(xs, p) == Project(xtl, p);
          assert Project(ys, p) == Project(ytl, p);
          CountProject(xtl, ytl, p);
        }
    }
}

