      var a :| a in setA;
      var b :| b in setB && (a, b) in relation;
      var setA' := setA - {a};
      var setB' := setB - {b};

      // Verify the four bijection preconditions hold for setA' and setB'

      // 1. Every a' in setA' maps to some b' in setB'
      forall a' | a' in setA'
      ensures exists b' :: b' in setB' && (a', b') in relation
      {
        assert a' in setA;
        var b' :| b' in setB && (a', b') in relation;
        // b' != b because a' != a and functionality
        if b' == b {
          // Then (a', b) in relation and (a, b) in relation, so a' == a by injectivity
          assert a' == a;
          assert false;
        }
        assert b' in setB';
      }

      // 2. Injectivity on setA'
      forall a1, a2, b' | a1 in setA' && a2 in setA' && b' in setB' && (a1, b') in relation && (a2, b') in relation
      ensures a1 == a2
      {
        assert a1 in setA && a2 in setA && b' in setB;
      }

      // 3. Every b' in setB' has a preimage in setA'
      forall b' | b' in setB'
      ensures exists a' :: a' in setA' && (a', b') in relation
      {
        assert b' in setB;
        var a' :| a' in setA && (a', b') in relation;
        // a' != a because b' != b and functionality
        if a' == a {
          // Then (a, b') in relation and (a, b) in relation, so b' == b by functionality
          assert b' == b;
          assert false;
        }
        assert a' in setA';
      }

      // 4. Functionality on setA'
      forall a', b1, b2 | b1 in setB' && b2 in setB' && a' in setA' && (a', b1) in relation && (a', b2) in relation
      ensures b1 == b2
      {
        assert a' in setA && b1 in setB && b2 in setB;
      }

      BijectivityImpliesEqualCardinality(setA', setB', relation);

      assert |setA'| == |setB'|;
      assert |setA| == |setA'| + 1;
      assert |setB| == |setB'| + 1;
    }

stats.proof_process_CrossProductCardinality:
if |setA| == 0 {
      assert setA == {};
      assert cp == {};
    } else {
      var x :| x in setA;
      var setA' := setA - {x};
      var cp' := set a, b | a in setA' && b in setB :: (a, b);
      var line := set b | b in setB :: (x, b);

      assert cp == cp' + line by {
        forall p | p in cp
          ensures p in cp' + line
        {
          var (a, b) := p;
          assert a in setA && b in setB;
          if a == x {
            assert p in line;
          } else {
            assert a in setA';
            assert p in cp';
          }
        }
        forall p | p in cp' + line
          ensures p in cp
        {
          if p in cp' {
            var (a, b) := p;
            assert a in setA' && b in setB;
            assert a in setA;
          } else {
            var (a, b) := p;
            assert a == x && b in setB;
            assert a in setA;
          }
        }
      }

      assert cp' !! line by {
        forall p | p in cp' && p in line
          ensures false
        {
          var (a, b) := p;
          assert a in setA' && a == x;
          assert x !in setA';
        }
      }

      var lineRelation : iset<((A,B), B)> := iset p : ((A,B), B) | p.0.1 == p.1 && p.0.0 == x && p.1 in setB && p.0 in line;

      assert |line| == |setB| by {
        assert forall p : (A,B) :: p in line ==> p.0 == x && p.1 in setB by {
          forall p : (A,B) | p in line ensures p.0 == x && p.1 in setB {
            var b :| b in setB && p == (x, b);
          }
        }
        assert forall a :: a in line ==> exists b :: b in setB && (a, b) in lineRelation by {
          forall a | a in line ensures exists b :: b in setB && (a, b) in lineRelation {
            assert a.0 == x && a.1 in setB;
            assert (a, a.1) in lineRelation;
          }
        }
        assert forall b :: b in setB ==> exists a :: a in line && (a, b) in lineRelation by {
          forall b | b in setB ensures exists a :: a in line && (a, b) in lineRelation {
            assert (x, b) in line;
            assert ((x, b), b) in lineRelation;
          }
        }
        BijectivityImpliesEqualCardinality(line, setB, lineRelation);
      }

      CrossProductCardinality(setA', setB, cp');

      assert |setA'| == |setA| - 1;
      assert |cp| == |cp'| + |line|;
      assert |cp'| == |setA'| * |setB|;
      assert |cp| == |setA| * |setB|;
    }

stats.proof_process_CardinalitySetRange:
if n == 0 {
} else {
  CardinalitySetRange(n - 1);
  assert SetRange(n) == SetRange(n - 1) + {n - 1};
}
